        char* count_for_desc = FindDlgItem(dlg, 204);
        int creature_id_for_desc = *(int*)((char*)dlg + 0x60);
        if (count_for_desc && creature_id_for_desc >= 0 && creature_id_for_desc < 197) {
            char* table = *(char**)0x6747B0;
