        if (!s_ok_btn[0]) {
            s_ok_btn[0] = LoadPcx24CompositeAsPcx8("bv_frmL.pcx", "bv_ok0.pcx", palSrc);
            s_ok_btn[1] = LoadPcx24CompositeAsPcx8("bv_frmL.pcx", "bv_ok1.pcx", palSrc);
