        case eMsgCommand::WHEEL_BUTTON:
            if (msg.subtype != eMsgSubtype::MOUSE_WHEEL_BUTTON_DOWN ||
                msg.subtype != eMsgSubtype::MOUSE_WHEEL_BUTTON_UP)
