// 右键弹出的魔法详情等通用对话框包含 H3DlgScrollableText 时，
// 滚轮消息直接转发给所有可滚动文本控件，与鼠标位置无关。
// 由于 H3 原版消息循环不把 WM_MOUSEWHEEL 转发给 DefProc，
// 用 WH_GETMESSAGE 钩子在消息泵层拦截。
// 对话框指针通过 Hook 创建函数缓存获得。
static HHOOK s_wheel_hook = nullptr;

// 缓存最近创建的 H3DlgScrollableText 指针（右键弹窗是模态的，同一时间只有一个）
static char* s_last_scrollable_text = nullptr;

// Hook H3DlgScrollableText::Create (0x5BA360)，缓存创建的控件指针
static int __stdcall Hook_CreateScrollableText(LoHook* /*h*/, HookContext* c)
{
    // 返回值在 eax = 新创建的对象指针
    // 这个 LoHook 在 call 之后执行，eax 是返回值
    s_last_scrollable_text = (char*)c->eax;
    WriteLog("[Wheel] H3DlgScrollableText 创建=%p", s_last_scrollable_text);
    return EXEC_DEFAULT;
}

static void ProcessWheelForScrollableText(char* scrollable_text, int wheel_delta)
{
    if (!scrollable_text) return;
    __try {
        char* scroll_bar = *(char**)(scrollable_text + 0x54);
        if (!scroll_bar) return;

        int tick_count = *(int*)(scroll_bar + 0x48);
        if (tick_count < 2) return;

        int tick = *(int*)(scroll_bar + 0x3C);
        int direction = (wheel_delta < 0) ? 1 : -1;
        int new_tick = tick + direction;
        if (new_tick < 0) new_tick = 0;
        if (new_tick >= tick_count) new_tick = tick_count - 1;
        if (new_tick != tick) {
            THISCALL_2(void, 0x5964D0, scroll_bar, new_tick);
            THISCALL_1(void, 0x596520, scroll_bar);
            WriteLog("[Wheel] 滚动成功 tick %d→%d", tick, new_tick);
        }
    } __except (EXCEPTION_EXECUTE_HANDLER) {
        WriteLog("[Wheel] ProcessWheelForScrollableText 异常");
    }
}

static LRESULT CALLBACK WheelGetMsgProc(int code, WPARAM wParam, LPARAM lParam)
{
    if (code == HC_ACTION && wParam == PM_REMOVE) {
        MSG* m = (MSG*)lParam;
        if (m->message == WM_MOUSEWHEEL) {
            short delta = (short)HIWORD(m->wParam);
            if (s_last_scrollable_text) {
                WriteLog("[Wheel] delta=%d 使用缓存的可滚动文本=%p", delta, s_last_scrollable_text);
                ProcessWheelForScrollableText(s_last_scrollable_text, delta);
            }
        }
    }
    return CallNextHookEx(nullptr, code, wParam, lParam);
}

