            if (cur) { ProcessWheelForDlg(cur, delta); handled = true; }
            if (cur2) { ProcessWheelForDlg(cur2, delta); handled = true; }
            if (cur3) { ProcessWheelForDlg(cur3, delta); handled = true; }

            if (!handled) {
                // 方法4：扫描常见 H3 对话框全局地址范围
                static const int scan_offsets[] = { 0x04, 0x08, 0x0C, 0x10, 0x14, 0x18, 0x1C, 0x20, 0x24, 0x28, 0x2C, 0x30, 0x34, 0x38, 0x3C, 0x40, 0x44, 0x48, 0x4C, 0x50 };
                for (int off : scan_offsets) {
                    _Dlg_* candidate = nullptr;
                    __try { candidate = *(_Dlg_**)(0x6992D0 + off); } __except(EXCEPTION_EXECUTE_HANDLER) { continue; }
                    if (candidate && candidate != (_Dlg_*)1) {
                        unsigned short w = 0, h = 0;
                        __try { w = *(unsigned short*)((char*)candidate + 0x20); h = *(unsigned short*)((char*)candidate + 0x22); } __except(EXCEPTION_EXECUTE_HANDLER) { continue; }
                        if (w > 50 && w < 2000 && h > 50 && h < 2000) {
                            WriteLog("[Wheel] 找到候选对话框 @0x6992D0+0x%X = %p (%hux%hu)", off, candidate, w, h);
                            ProcessWheelForDlg(candidate, delta);
                        }
                    }
                }
            }
        }
    }
    return CallNextHookEx(nullptr, code, wParam, lParam);
}

// HiHook 0x41B120（_Dlg_::DefProc）：通用滚轮处理 + 生物信息窗口兜底。
int __stdcall Hook_DlgDefProc(HiHook* h, _Dlg_* dlg, _EventMsg_* msg)
{
    // DefProc 不处理 MOUSE_WHEEL（H3 原版消息循环不转发），滚轮由 WH_GETMESSAGE 钩子处理。

    // 严格过滤：只有 298×cfg.window_height 且包含 id=200 背景控件的对话框才处理。
    // 避免存档/读档/其它对话框进入后遍历未初始化的 item 数组导致崩溃。
    if (dlg && dlg->width == 298 && dlg->height == cfg.window_height && FindDlgItem(dlg, 200)) {
        AdjustCreatureInfoDlg(dlg);
    }
    return THISCALL_2(int, h->GetDefaultFunc(), dlg, msg);
}

