static LRESULT CALLBACK WheelGetMsgProc(int code, WPARAM wParam, LPARAM lParam)
{
    if (code == HC_ACTION && wParam == PM_REMOVE) {
        MSG* m = (MSG*)lParam;
        if (m->message == WM_WHEEL_REDRAW) {
            // 延迟重绘：此时已脱离 PeekMessage 内部，渲染状态应该安全
            if (s_pending_redraw_scrollbar) {
                __try {
                    void** vt = *(void***)s_pending_redraw_scrollbar;
                    if (vt && vt[4]) {
                        THISCALL_1(void, (DWORD)vt[4], s_pending_redraw_scrollbar);
                    }
                } __except (EXCEPTION_EXECUTE_HANDLER) {
                    WriteLog("[Wheel] 延迟重绘异常");
                }
                s_pending_redraw_scrollbar = nullptr;
            }
            m->message = WM_NULL; // 消化掉
        }
        else if (m->message == WM_MOUSEWHEEL) {
            short delta = (short)HIWORD(m->wParam);
            WriteLog("[Wheel] delta=%d cached_st=%p", delta, s_last_scrollable_text);
            ProcessWheelForScrollableText(s_last_scrollable_text, delta);
        }
    }
    return CallNextHookEx(nullptr, code, wParam, lParam);
}

