if (new_tick != tick) {
    // 1. SetTick：更新滚动位置数据
    THISCALL_2(void, 0x5964D0, scroll_bar, new_tick);

    // 2. 设置 dirty flag（state |= 1），让游戏自己的绘制循环重绘滚动条。
    //    SetTick 不设置此标志；游戏正常滚动时 FUN_00596520 会设置它。
    //    没有这个标志，对话框绘制循环不会调 scrollbar->Draw()，滑块就不动。
    *(unsigned char*)(scroll_bar + 0x16) |= 1;

    // 3. vScrollCallOwner：通知所有者文本控件更新内容
    if (sb_vt && sb_vt[16]) {
        THISCALL_1(void, (DWORD)sb_vt[16], scroll_bar);
    }
    WriteLog("[Wheel] tick=%d → %d", tick, new_tick);
}

