static void ProcessWheelForScrollableText(char* st, int wheel_delta)
{
    if (!st) return;
    __try {
        char* scroll_bar = *(char**)(st + 0x54);
        if (!scroll_bar) { WriteLog("[Wheel] 无滚动条"); return; }

        int tick_count = *(int*)(scroll_bar + 0x48);
        if (tick_count < 2) { WriteLog("[Wheel] tickCount=%d 不需滚动", tick_count); return; }

        // 合成 H3Msg，模拟 KEY_DOWN 消息发送给滚动条。
        // 滚动条的 vProcessMsg (FUN_005967d0) 处理 KEY_DOWN：
        //   VK_UP(0x48) → FUN_00596520(1,2,0,4,0x48) → 滚动 + 重绘滑块 + 通知所有者
        //   VK_DOWN(0x49) → FUN_00596520(1,2,0,4,0x49)
        // 这走的是游戏原生路径，所有数据更新和渲染都由游戏代码完成。
        short sb_id = *(short*)(scroll_bar + 0x10);
        int vk = (wheel_delta < 0) ? 0x49 : 0x48; // 向下滚 = VK_DOWN，向上滚 = VK_UP

        // H3Msg 布局：command(4), subtype(4), itemId(4), flags(4), xpos(4), ypos(4), param(4), parentDlg(4)
        int msg_buf[8] = { 0 };
        msg_buf[0] = 4;       // eMsgCommand::KEY_DOWN
        msg_buf[1] = vk;      // virtual key code
        msg_buf[2] = sb_id;   // target item id
        msg_buf[6] = vk;      // also in param field (game checks param_2[6])

        void** sb_vt = *(void***)scroll_bar;
        int tick = *(int*)(scroll_bar + 0x3C);
        WriteLog("[Wheel] st=%p sb=%p tick=%d/%d vk=0x%X id=%d", st, scroll_bar, tick, tick_count, vk, sb_id);

        // 调用滚动条的 vProcessMsg (vtable offset 0x08 = slot 2)
        if (sb_vt && sb_vt[2]) {
            THISCALL_2(int, (DWORD)sb_vt[2], scroll_bar, msg_buf);
            WriteLog("[Wheel] vProcessMsg 完成 tick=%d", *(int*)(scroll_bar + 0x3C));
        }
    } __except (EXCEPTION_EXECUTE_HANDLER) {
        WriteLog("[Wheel] ProcessWheel 异常 code=0x%08X", GetExceptionCode());
    }
}

