        WriteLog("[RangedOverlayPanel][Diag] Recalculate done reason=%s mgr=%p checksum=0x%08X->0x%08X ranged=(%d,%d) spell=(%d,%d) total=(%d,%d) %s",
            reason ? reason : "", mgr, old_checksum, stack_checksum_, ranged[0], ranged[1], spell[0], spell[1], total[0], total[1], summary);
    }

