    __try {
        RECT src_rect = { 0, 0, bg->width, bg->height };
        RECT dst_rect = { dst_x, dst_y, dst_x + dst_w, dst_y + dst_h };
        HRESULT hr = o_DDSurfaceBackBuffer->Blt(&dst_rect, bg->dd_surface, &src_rect, DDBLT_WAIT, nullptr);
        if (FAILED(hr)) {
