// 通过 DirectDraw 离屏 surface 绘制背景图。
// 解码 PCX → RGBA → 创建 DD 离屏 surface → Lock 写入像素 → Blt 到 backbuffer。
// 完全绕开 HD_TC2 hook 和 screen_pcx16 buffer。

struct DDBackgroundSurface
{
    LPDIRECTDRAWSURFACE dd_surface;
    int width;
    int height;
};

static const _word_ TEXT_MASK_SENTINEL_565 = 0xF81F;

static DDBackgroundSurface* CreateEmptyDDSurface(int w, int h)
{
    if (w <= 0 || h <= 0 || !o_DD) return nullptr;
    DDSURFACEDESC ddsd;
    memset(&ddsd, 0, sizeof(ddsd));
    ddsd.dwSize = sizeof(ddsd);
    ddsd.dwFlags = DDSD_CAPS | DDSD_WIDTH | DDSD_HEIGHT;
    ddsd.ddsCaps.dwCaps = DDSCAPS_OFFSCREENPLAIN;
    ddsd.dwWidth = w;
    ddsd.dwHeight = h;

    LPDIRECTDRAWSURFACE surf = nullptr;
    HRESULT hr = o_DD->CreateSurface(&ddsd, &surf, nullptr);
    if (FAILED(hr) || !surf) {
        WriteLog("[DDBackground] Create empty surface failed hr=0x%08X w=%d h=%d", hr, w, h);
        return nullptr;
    }

    DDBackgroundSurface* bg = new DDBackgroundSurface();
    bg->dd_surface = surf;
    bg->width = w;
    bg->height = h;
    return bg;
}

static DDBackgroundSurface* CreateDDBackground(const char* pcx_path)
{
    // 解码 PCX
    unsigned char* data = nullptr;
    int size = 0;
    if (!ReadWholeFile(pcx_path, &data, &size)) return nullptr;
    if (size < 128) { free(data); return nullptr; }

    int bpp = data[3];
    int xmin = *(short*)(data + 4);
    int ymin = *(short*)(data + 6);
    int xmax = *(short*)(data + 8);
    int ymax = *(short*)(data + 10);
    int nplanes = data[65];
    int bpl = *(short*)(data + 66);
    int w = xmax - xmin + 1;
    int h = ymax - ymin + 1;

    if (w <= 0 || h <= 0 || w > 4096 || h > 4096) { free(data); return nullptr; }
    if (!(nplanes == 1 && bpp == 8)) { free(data); return nullptr; }

    int rawSize = bpl * h;
    unsigned char* raw = (unsigned char*)malloc(rawSize);
    if (!raw) { free(data); return nullptr; }

    int pos = 128, rp = 0;
    while (rp < rawSize && pos < size) {
        unsigned char b = data[pos++];
        if ((b & 0xC0) == 0xC0) {
            int cnt = b & 0x3F;
            if (pos >= size) break;
            unsigned char val = data[pos++];
            for (int i = 0; i < cnt && rp < rawSize; ++i) raw[rp++] = val;
        } else {
            raw[rp++] = b;
        }
    }
    if (rp < rawSize) {
        WriteLog("[DDBackground] incomplete PCX data decoded=%d expected=%d", rp, rawSize);
        free(raw);
        free(data);
        return nullptr;
    }

    unsigned char pal[768] = {0};
    bool palFound = false;
    if (size >= 769 && data[size - 769] == 0x0C) {
        memcpy(pal, data + (size - 768), 768);
        palFound = true;
    }
    if (!palFound) {
        for (int i = size - 769; i >= 0; --i) {
            if (data[i] == 0x0C && i + 768 < size) {
                memcpy(pal, data + i + 1, 768);
                palFound = true;
                break;
            }
        }
    }
    if (!palFound) {
        WriteLog("[DDBackground] PCX palette not found");
        free(raw);
        free(data);
        return nullptr;
    }
    free(data);

    // 创建 DirectDraw 离屏 surface (16-bit RGB565)
    DDSURFACEDESC ddsd;
    memset(&ddsd, 0, sizeof(ddsd));
    ddsd.dwSize = sizeof(ddsd);
    ddsd.dwFlags = DDSD_CAPS | DDSD_WIDTH | DDSD_HEIGHT;
    ddsd.ddsCaps.dwCaps = DDSCAPS_OFFSCREENPLAIN;
    ddsd.dwWidth = w;
    ddsd.dwHeight = h;

    LPDIRECTDRAWSURFACE dd_surf = nullptr;
    HRESULT hr = o_DD->CreateSurface(&ddsd, &dd_surf, nullptr);
    if (FAILED(hr) || !dd_surf) {
        WriteLog("[DDBackground] CreateSurface failed hr=0x%08X w=%d h=%d", hr, w, h);
        free(raw);
        return nullptr;
    }

    // Lock surface 并写入 RGB565 像素
    DDSURFACEDESC lock_desc;
    memset(&lock_desc, 0, sizeof(lock_desc));
    lock_desc.dwSize = sizeof(lock_desc);
    hr = dd_surf->Lock(nullptr, &lock_desc, DDLOCK_WAIT | DDLOCK_SURFACEMEMORYPTR, nullptr);
    if (FAILED(hr)) {
        WriteLog("[DDBackground] Lock failed hr=0x%08X", hr);
        dd_surf->Release();
        free(raw);
        return nullptr;
    }

    _word_* dst_row = (_word_*)((_byte_*)lock_desc.lpSurface);
    int dst_pitch_pixels = lock_desc.lPitch >> 1;

    // 检测像素格式
    DDPIXELFORMAT pf;
    memset(&pf, 0, sizeof(pf));
    pf.dwSize = sizeof(pf);
    dd_surf->GetPixelFormat(&pf);

    if (pf.dwRGBBitCount == 16) {
        // 16-bit：直接写 RGB565
        for (int y = 0; y < h; y++) {
            _word_* d = dst_row + y * dst_pitch_pixels;
            _byte_* s = raw + y * bpl;
            for (int x = 0; x < w; x++) {
                unsigned char idx = s[x];
                d[x] = RGB565_fromR8G8B8(pal[idx * 3], pal[idx * 3 + 1], pal[idx * 3 + 2]);
            }
        }
    } else if (pf.dwRGBBitCount == 32) {
        // 32-bit：写 RGBA
        _dword_* d32 = (_dword_*)lock_desc.lpSurface;
        int dst_pitch32 = lock_desc.lPitch >> 2;
        for (int y = 0; y < h; y++) {
            _dword_* d = d32 + y * dst_pitch32;
            _byte_* s = raw + y * bpl;
            for (int x = 0; x < w; x++) {
                unsigned char idx = s[x];
                d[x] = (0xFF << 24) | (pal[idx * 3] << 16) | (pal[idx * 3 + 1] << 8) | pal[idx * 3 + 2];
            }
        }
    } else {
        WriteLog("[DDBackground] unsupported bpp=%d", pf.dwRGBBitCount);
        dd_surf->Unlock(nullptr);
        dd_surf->Release();
        free(raw);
        return nullptr;
    }

    dd_surf->Unlock(nullptr);
    free(raw);

    DDBackgroundSurface* bg = new DDBackgroundSurface();
    bg->dd_surface = dd_surf;
    bg->width = w;
    bg->height = h;
    return bg;
}

static void DestroyDDBackground(DDBackgroundSurface* bg)
{
    if (!bg) return;
    if (bg->dd_surface) { bg->dd_surface->Release(); bg->dd_surface = nullptr; }
    delete bg;
}

static void DrawDDBackground(DDBackgroundSurface* bg, int dst_x, int dst_y, int dst_w, int dst_h)
{
    if (!bg || !bg->dd_surface) return;
    __try {
        RECT src_rect = { 0, 0, bg->width, bg->height };
        RECT dst_rect = { dst_x, dst_y, dst_x + dst_w, dst_y + dst_h };
        HRESULT hr = o_DDSurfaceBackBuffer->Blt(&dst_rect, bg->dd_surface, &src_rect, DDBLT_WAIT, nullptr);
        if (FAILED(hr)) {
            WriteLog("[DDBackground] Blt failed hr=0x%08X", hr);
        }
    } __except (EXCEPTION_EXECUTE_HANDLER) {
        WriteLog("[DDBackground] SEH exception during Blt dst=(%d,%d,%d,%d)", dst_x, dst_y, dst_w, dst_h);
    }
}

static bool CopyBackBufferToSurface(DDBackgroundSurface* dst, int src_x, int src_y, int w, int h)
{
    if (!dst || !dst->dd_surface || !o_DDSurfaceBackBuffer || w <= 0 || h <= 0) return false;
    __try {
        RECT src_rect = { src_x, src_y, src_x + w, src_y + h };
        RECT dst_rect = { 0, 0, w, h };
        HRESULT hr = dst->dd_surface->Blt(&dst_rect, o_DDSurfaceBackBuffer, &src_rect, DDBLT_WAIT, nullptr);
        if (FAILED(hr)) {
            WriteLog("[DDBackground] Save underlay failed hr=0x%08X", hr);
            return false;
        }
        return true;
    } __except (EXCEPTION_EXECUTE_HANDLER) {
        WriteLog("[DDBackground] SEH exception during save underlay rect=(%d,%d,%d,%d)", src_x, src_y, w, h);
        return false;
    }
}

static bool RestoreSurfaceToBackBuffer(DDBackgroundSurface* src, int dst_x, int dst_y, int w, int h)
{
    if (!src || !src->dd_surface || !o_DDSurfaceBackBuffer || w <= 0 || h <= 0) return false;
    __try {
        RECT src_rect = { 0, 0, w, h };
        RECT dst_rect = { dst_x, dst_y, dst_x + w, dst_y + h };
        HRESULT hr = o_DDSurfaceBackBuffer->Blt(&dst_rect, src->dd_surface, &src_rect, DDBLT_WAIT, nullptr);
        if (FAILED(hr)) {
            WriteLog("[DDBackground] Restore underlay failed hr=0x%08X", hr);
            return false;
        }
        return true;
    } __except (EXCEPTION_EXECUTE_HANDLER) {
        WriteLog("[DDBackground] SEH exception during restore underlay rect=(%d,%d,%d,%d)", dst_x, dst_y, w, h);
        return false;
    }
}

static void FillPcx16Mask(_Pcx16_* pcx, _word_ color)
{
    if (!pcx || !pcx->buffer || pcx->width <= 0 || pcx->height <= 0) return;
    int bytes_per_pixel = (H3BitMode::Get() == 4) ? 4 : 2;
    _byte_* row = pcx->buffer;
    int active_bytes = pcx->width * bytes_per_pixel;
    for (int y = 0; y < pcx->height; ++y) {
        if (bytes_per_pixel == 2) {
            _word_* p = (_word_*)row;
            for (int x = 0; x < pcx->width; ++x) p[x] = color;
        } else {
            _dword_* p = (_dword_*)row;
            for (int x = 0; x < pcx->width; ++x) p[x] = 0xFFFF00FF;
        }
        row += pcx->scanlineSize > 0 ? pcx->scanlineSize : active_bytes;
    }
}

static bool EnsureTextMask(_Pcx16_** mask, int w, int h)
{
    if (w <= 0 || h <= 0) return false;
    if (*mask && ((*mask)->width != w || (*mask)->height != h)) {
        (*mask)->Destroy();
        *mask = nullptr;
    }
    if (!*mask) {
        *mask = _Pcx16_::Create(w, h);
        if (!*mask) {
            WriteLog("[RangedOverlayPanel] Create text mask failed w=%d h=%d", w, h);
            return false;
        }
    }
    return true;
}

static void ReleaseTextMask(_Pcx16_** mask)
{
    if (!mask || !*mask) return;
    (*mask)->Destroy();
    *mask = nullptr;
}

static int DrawTextMaskToBackBuffer(_Pcx16_* mask, int dst_x, int dst_y)
{
    if (!mask || !mask->buffer || !o_DDSurfaceBackBuffer) return -1;
    static int unsupported_bpp_logs = 0;
    bool locked = false;
    int copied_pixels = 0;
    __try {
        DDPIXELFORMAT pf;
        memset(&pf, 0, sizeof(pf));
        pf.dwSize = sizeof(pf);
        HRESULT pf_hr = o_DDSurfaceBackBuffer->GetPixelFormat(&pf);
        int bpp = SUCCEEDED(pf_hr) ? (int)pf.dwRGBBitCount : 0;
        if (!bpp) bpp = (H3BitMode::Get() == 4) ? 32 : 16;

        DDSURFACEDESC desc;
        memset(&desc, 0, sizeof(desc));
        desc.dwSize = sizeof(desc);
        HRESULT hr = o_DDSurfaceBackBuffer->Lock(nullptr, &desc, DDLOCK_WAIT | DDLOCK_SURFACEMEMORYPTR, nullptr);
        if (FAILED(hr)) {
            WriteLog("[RangedOverlayPanel] Lock backbuffer for text failed hr=0x%08X", hr);
            return -1;
        }
        locked = true;

        int copy_x = 0;
        int copy_y = 0;
        int copy_w = mask->width;
        int copy_h = mask->height;
        if (dst_x < 0) { copy_x = -dst_x; copy_w += dst_x; dst_x = 0; }
        if (dst_y < 0) { copy_y = -dst_y; copy_h += dst_y; dst_y = 0; }
        if (desc.dwWidth && dst_x + copy_w > (int)desc.dwWidth) copy_w = (int)desc.dwWidth - dst_x;
        if (desc.dwHeight && dst_y + copy_h > (int)desc.dwHeight) copy_h = (int)desc.dwHeight - dst_y;
        if (copy_w <= 0 || copy_h <= 0) {
            o_DDSurfaceBackBuffer->Unlock(nullptr);
            locked = false;
            return 0;
        }

        if (bpp == 16) {
            for (int row = 0; row < copy_h; ++row) {
                _word_* src = (_word_*)(mask->buffer + (copy_y + row) * mask->scanlineSize) + copy_x;
                _word_* dst = (_word_*)((_byte_*)desc.lpSurface + (dst_y + row) * desc.lPitch) + dst_x;
                for (int col = 0; col < copy_w; ++col) {
                    if (src[col] != TEXT_MASK_SENTINEL_565) {
                        dst[col] = src[col];
                        ++copied_pixels;
                    }
                }
            }
        } else if (bpp == 32) {
            for (int row = 0; row < copy_h; ++row) {
                _dword_* dst = (_dword_*)((_byte_*)desc.lpSurface + (dst_y + row) * desc.lPitch) + dst_x;
                if (H3BitMode::Get() == 4) {
                    _dword_* src32 = (_dword_*)(mask->buffer + (copy_y + row) * mask->scanlineSize) + copy_x;
                    for (int col = 0; col < copy_w; ++col) {
                        if (src32[col] != 0xFFFF00FF) {
                            dst[col] = src32[col];
                            ++copied_pixels;
                        }
                    }
                } else {
                    _word_* src16 = (_word_*)(mask->buffer + (copy_y + row) * mask->scanlineSize) + copy_x;
                    for (int col = 0; col < copy_w; ++col) {
                        if (src16[col] != TEXT_MASK_SENTINEL_565) {
                            _word_ p = src16[col];
                            unsigned r = ((p >> 11) & 0x1F) << 3;
                            unsigned g = ((p >> 5) & 0x3F) << 2;
                            unsigned b = (p & 0x1F) << 3;
                            dst[col] = 0xFF000000 | (r << 16) | (g << 8) | b;
                            ++copied_pixels;
                        }
                    }
                }
            }
        } else {
            if (unsupported_bpp_logs < 3) {
                ++unsupported_bpp_logs;
                WriteLog("[RangedOverlayPanel] unsupported backbuffer bpp for text=%d", bpp);
            }
        }

        o_DDSurfaceBackBuffer->Unlock(nullptr);
        locked = false;
        return copied_pixels;
    } __except (EXCEPTION_EXECUTE_HANDLER) {
        if (locked) o_DDSurfaceBackBuffer->Unlock(nullptr);
        WriteLog("[RangedOverlayPanel] SEH exception during DrawTextMaskToBackBuffer dst=(%d,%d)", dst_x, dst_y);
        return -1;
    }
}

static void SafeDrawText(_Fnt_* font, _Pcx16_* target, const char* text, int x, int y, int w, int h, int color, int align)
{
    if (!font || !target || !text) return;
    __try {
        font->TextDraw(target, text, x, y, w, h, (eTextColor)color, (eTextAlignment)align);
    } __except (EXCEPTION_EXECUTE_HANDLER) {
        WriteLog("[RangedOverlayPanel] SEH exception during TextDraw text='%s' rect=(%d,%d,%d,%d)", text, x, y, w, h);
    }
}

