class RangedOverlayPanel
{
public:
    RangedOverlayPanel()
    {
        ResetRuntimeState();
    }

    void MarkDirty(const char* /*reason*/)
    {
        dirty_ = true;
    }

    void BeginManualBattle(_BattleMgr_* mgr, const char* reason)
    {
        last_mgr_ = mgr;
        active_ = true;
        manual_battle_started_ = true;
        suppressed_for_result_ = false;
        stack_checksum_ = 0;
        ResetText();
        MarkDirty(reason);
    }

    void Destroy()
    {
        active_ = false;
        manual_battle_started_ = false;
        suppressed_for_result_ = false;
        ReleaseBackground();
        ResetText();
        if (o_BattleMgr) o_BattleMgr->RedrawBattlefield(FALSE, TRUE, FALSE, 0, TRUE, FALSE);
    }

    void Draw(_BattleMgr_* mgr)
    {
        DrawImpl(mgr);
    }

    void DrawImpl(_BattleMgr_* mgr)
    {
        _Dlg_* dlg = (mgr && mgr->dlg && (uint32_t)mgr->dlg > 0x10000) ? mgr->dlg : nullptr;
        _Dlg_* active_dlg = GetActiveDlg();
        _Pcx16_* screen = o_WndMgr ? o_WndMgr->screen_pcx16 : nullptr;
        if (!screen || !dlg) return;

        if (last_mgr_ != mgr) {
            last_mgr_ = mgr;
            active_ = false;
            manual_battle_started_ = false;
            suppressed_for_result_ = false;
            stack_checksum_ = 0;
            ResetText();
            MarkDirty("new battle manager");
        }

        if (last_dlg_ != dlg) {
            last_dlg_ = dlg;
            stack_checksum_ = 0;
            ResetText();
            ReleaseBackground();
            MarkDirty("new battle dialog");
        }

        if (!manual_battle_started_) return;

        if (IsReplayableQuickBattleResultDlg(active_dlg)) {
            SuppressForResult("replayable quick battle result", mgr, active_dlg);
            return;
        }
        if (IsBattleOverByEngine(mgr)) {
            SuppressForResult("battle over", mgr, active_dlg);
            return;
        }
        if (IsHiddenBattleByEngine(mgr)) {
            SuppressForResult("hidden battle", mgr, active_dlg);
            return;
        }
        if (suppressed_for_result_ && manual_battle_started_) {
            active_ = true;
            suppressed_for_result_ = false;
            stack_checksum_ = 0;
            ResetText();
            MarkDirty("re-enter manual battle");
        }

        if (!active_) return;
        if (suppressed_for_result_) return;

        int panel_w = cfg.ranged_panel_width;
        int panel_h = cfg.ranged_panel_height;
        int text_h = 17;

        int battle_x = (screen->width - 800) / 2;
        int battle_y = (screen->height - 600) / 2;
        if (battle_x < 0) battle_x = 0;
        if (battle_y < 0) battle_y = 0;

        int x = battle_x + (800 - panel_w) / 2;
        if (x < 0) x = 0;
        int y = battle_y - panel_h - RP_BASE_Y_OFFSET - cfg.ranged_panel_y;
        if (y < 0) y = 0;

        int pad_x = 16;
        int mid_gap = 16;
        int col_w = (panel_w - pad_x * 2 - mid_gap) / 2;
        if (col_w < 40) col_w = panel_w / 2;

        EnsureBackground();
        if (!bg_) return;

        // 每帧重算：战斗中单位数量/状态不断变化，不缓存。
        Recalculate(mgr);

        // 1. 画背景到 screen_pcx16：覆盖旧文字，HD_TC2 会正确合成。
        __try {
            bg_->DrawToPcx16(x, y, FALSE, screen);
        } __except (EXCEPTION_EXECUTE_HANDLER) {
            WriteLog("[RangedOverlayPanel] SEH exception during DrawToPcx16 dst=(%d,%d)", x, y);
        }

        // 2. 画文字到 screen_pcx16。
        _Fnt_* font = GetRangedPanelTextFont();
        if (font) {
            for (int row = 0; row < 3; ++row) {
                int yy = y + cfg.row_y[row];
                // 左列（攻击方）右对齐
                SafeDrawTextToScreen(font, screen, text_[row * 2],
                    x + pad_x, yy, col_w, text_h,
                    cfg.ranged_panel_text_color, 2);
                // 右列（防御方）左对齐
                SafeDrawTextToScreen(font, screen, text_[row * 2 + 1],
                    x + panel_w - pad_x - col_w, yy, col_w, text_h,
                    cfg.ranged_panel_text_color, 0);
            }
        }

        MaybeLogDraw(mgr);
    }

    bool Active() const { return active_; }

private:
    void ResetRuntimeState()
    {
        bg_ = nullptr;
        bg_load_failed_ = false;
        last_dlg_ = nullptr;
        last_mgr_ = nullptr;
        active_ = false;
        manual_battle_started_ = false;
        suppressed_for_result_ = false;
        dirty_ = true;
        stack_checksum_ = 0;
        ranged_value_[0] = 0;
        ranged_value_[1] = 0;
        spell_value_[0] = 0;
        spell_value_[1] = 0;
        total_value_[0] = 0;
        total_value_[1] = 0;
        debug_draw_seq_ = 0;
        debug_last_ranged_[0] = -1;
        debug_last_ranged_[1] = -1;
        debug_last_spell_[0] = -1;
        debug_last_spell_[1] = -1;
        debug_last_total_[0] = -1;
        debug_last_total_[1] = -1;
        debug_last_summary_[0][0] = 0;
        debug_last_summary_[1][0] = 0;
        ResetText();
    }

    void ResetText()
    {
        memset(text_, 0, sizeof(text_));
        dirty_ = true;
    }

    void EnsureBackground()
    {
        if (!bg_ && !bg_load_failed_) {
            char modulePath[MAX_PATH];
            GetModuleFileNameA(g_hModule, modulePath, MAX_PATH);
            char* slash = strrchr(modulePath, '\\');
            if (slash) slash[1] = 0; else modulePath[0] = 0;
            char path[2048];
            _snprintf(path, sizeof(path) - 1, "%simg\\%s", modulePath, cfg.ranged_panel_image);
            path[sizeof(path) - 1] = 0;
            bg_ = CreatePcx16Background(path);
            bg_load_failed_ = (bg_ == nullptr);
        }
    }

    void ReleaseBackground()
    {
        if (bg_) { bg_->Destroy(); bg_ = nullptr; }
        bg_load_failed_ = false;
    }

    void SuppressForResult(const char* reason, _BattleMgr_* mgr, _Dlg_* active_dlg)
    {
        (void)reason;
        (void)mgr;
        (void)active_dlg;
        active_ = false;
        suppressed_for_result_ = true;
        ReleaseBackground();
        ResetText();
    }

    void Recalculate(_BattleMgr_* mgr)
    {
        if (!mgr) return;

        unsigned int checksum = 0;
        if (!SafeComputeStackChecksum(mgr, &checksum)) return;

        int ranged[2] = { 0, 0 };
        int spell[2] = { 0, 0 };
        if (!SafeCalcRangedUnitsPower(mgr, 0, &ranged[0]) ||
            !SafeCalcRangedUnitsPower(mgr, 1, &ranged[1]) ||
            !SafeCalcHeroSpellPower(mgr, 0, &spell[0]) ||
            !SafeCalcHeroSpellPower(mgr, 1, &spell[1])) {
            return;
        }
        stack_checksum_ = checksum;
        int total[2] = { ranged[0] + spell[0], ranged[1] + spell[1] };

        ranged_value_[0] = ranged[0];
        ranged_value_[1] = ranged[1];
        spell_value_[0] = spell[0];
        spell_value_[1] = spell[1];
        total_value_[0] = total[0];
        total_value_[1] = total[1];

        _snprintf(text_[0], sizeof(text_[0]) - 1, "%d", ranged[0]);
        _snprintf(text_[1], sizeof(text_[1]) - 1, "%d", ranged[1]);
        _snprintf(text_[2], sizeof(text_[2]) - 1, "%d", spell[0]);
        _snprintf(text_[3], sizeof(text_[3]) - 1, "%d", spell[1]);
        _snprintf(text_[4], sizeof(text_[4]) - 1, "%d", total[0]);
        _snprintf(text_[5], sizeof(text_[5]) - 1, "%d", total[1]);
        for (int i = 0; i < 6; ++i) text_[i][sizeof(text_[i]) - 1] = 0;

        dirty_ = false;
    }

    void MaybeLogDraw(_BattleMgr_* mgr)
    {
        ++debug_draw_seq_;

        char summary0[768];
        char summary1[768];
        BuildRangedSideSummary(mgr, 0, summary0, sizeof(summary0));
        BuildRangedSideSummary(mgr, 1, summary1, sizeof(summary1));

        bool value_changed =
            ranged_value_[0] != debug_last_ranged_[0] ||
            ranged_value_[1] != debug_last_ranged_[1] ||
            spell_value_[0] != debug_last_spell_[0] ||
            spell_value_[1] != debug_last_spell_[1] ||
            total_value_[0] != debug_last_total_[0] ||
            total_value_[1] != debug_last_total_[1];

        bool summary_changed =
            strcmp(summary0, debug_last_summary_[0]) != 0 ||
            strcmp(summary1, debug_last_summary_[1]) != 0;

        if (debug_draw_seq_ <= 8 || value_changed || summary_changed) {
            WriteLog("[Diag] draw=%u checksum=0x%08X ranged=%d/%d spell=%d/%d total=%d/%d",
                debug_draw_seq_, stack_checksum_,
                ranged_value_[0], ranged_value_[1], spell_value_[0], spell_value_[1],
                total_value_[0], total_value_[1]);
            WriteLog("[Diag] side0 %s", summary0);
            WriteLog("[Diag] side1 %s", summary1);

            debug_last_ranged_[0] = ranged_value_[0];
            debug_last_ranged_[1] = ranged_value_[1];
            debug_last_spell_[0] = spell_value_[0];
            debug_last_spell_[1] = spell_value_[1];
            debug_last_total_[0] = total_value_[0];
            debug_last_total_[1] = total_value_[1];
            strncpy(debug_last_summary_[0], summary0, sizeof(debug_last_summary_[0]) - 1);
            strncpy(debug_last_summary_[1], summary1, sizeof(debug_last_summary_[1]) - 1);
            debug_last_summary_[0][sizeof(debug_last_summary_[0]) - 1] = 0;
            debug_last_summary_[1][sizeof(debug_last_summary_[1]) - 1] = 0;
        }
    }

    _Pcx16_* bg_;
    bool bg_load_failed_;
    _Dlg_* last_dlg_;
    _BattleMgr_* last_mgr_;
    bool active_;
    bool manual_battle_started_;
    bool suppressed_for_result_;
    bool dirty_;

    unsigned int stack_checksum_;
    char text_[6][64];
    int ranged_value_[2];
    int spell_value_[2];
    int total_value_[2];
    unsigned int debug_draw_seq_;
    int debug_last_ranged_[2];
    int debug_last_spell_[2];
    int debug_last_total_[2];
    char debug_last_summary_[2][768];
};

