$draws = $log | Where-Object { $_ -match '\[Diag\] draw=' }
foreach ($d in $draws) {
    if ($d -match '\[(\d{2}:\d{2}:\d{2}\.\d+).*draw=(\d+)') {
        Write-Host "$($matches[1]) draw=$($matches[2])"
    }
} | Select-Object -First 5
# 实际输出前5和后5，以及看间隔
$lines = $draws | ForEach-Object { if ($_ -match '\[(\d{2}:\d{2}:\d{2}\.\d{3}).*draw=(\d+).*ranged=(\d+)') { "$($matches[1]) d=$($matches[2]) r=$($matches[3])" } }
Write-Host "=== First 5 ==="
$lines | Select-Object -First 5
Write-Host "=== Around draw 100 ==="
$lines | Select-Object -Skip 97 -First 5
Write-Host "=== Around draw 300 ==="
$lines | Select-Object -Skip 297 -First 5
Write-Host "=== Around draw 500 ==="
$lines | Select-Object -Skip 497 -First 5
Write-Host "=== Last 5 ==="
$lines | Select-Object -Last 5

$content = Get-Content "D:\Heroes3\Heroes3_2026.05.01\_HD3_Data\Packs\战斗价值信息\BattleValueInfo_20260705_172332.log" -Encoding UTF8
$drawLines = @()
foreach ($line in $content) {
    if ($line -match '\[(\d{4}-\d{2}-\d{2} \d{2}:\d{2}:\d{2}\.\d+)\].*draw=(\d+).*ranged=(\d+)/') {
        $drawLines += [PSCustomObject]@{ Time=$matches[1]; Draw=[int]$matches[2]; Ranged=[int]$matches[3] }
    }
}
# Group by second
$bySec = $drawLines | Group-Object { ($_.Time -split '\.')[0] } | Sort-Object Name
foreach ($g in $bySec) {
    $d = $g.Group.Draw
    $r = $g.Group.Ranged
    Write-Host "$($g.Name): draws $($d[0])-$($d[-1]) (n=$($g.Count)) ranged[$r[0]..$($r[-1])]"
}

