        int text_h = 17;

        int battle_x = (screen->width - 800) / 2;
        int battle_y = (screen->height - 600) / 2;
        if (battle_x < 0) battle_x = 0;
        if (battle_y < 0) battle_y = 0;

        int x = battle_x + (800 - panel_w) / 2;
        if (x < 0) x = 0;
        int y = battle_y - panel_h - RP_BASE_Y_OFFSET - cfg.ranged_panel_y;
