        _Fnt_* font = GetRangedPanelTextFont();
        if (font && EnsureTextMask(&text_mask_, panel_w, panel_h)) {
            FillPcx16Mask(text_mask_, TEXT_MASK_SENTINEL_565);
            for (int row = 0; row < 3; ++row) {
