+static bool EnsureTextMask(_Pcx16_** mask, int w, int h)
+{
+    if (!mask || w <= 0 || h <= 0) return false;
+    if (*mask && (*mask)->width == w && (*mask)->height == h && (*mask)->buffer) return true;
+    if (*mask) {
+        (*mask)->Destroy();
+        *mask = nullptr;
+    }
+    *mask = _Pcx16_::Create(w, h);
+    return *mask && (*mask)->buffer;
