+    if (!surface) return H3BitMode::Get() == 4 ? 32 : 16;
+    DDPIXELFORMAT pf;
+    memset(&pf, 0, sizeof(pf));
+    pf.dwSize = sizeof(pf);
+    if (SUCCEEDED(surface->GetPixelFormat(&pf)) && (pf.dwRGBBitCount == 16 || pf.dwRGBBitCount == 32))
